package com.google.gson.protobuf;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonArray;
import com.google.gson.JsonElement;
import com.google.gson.JsonObject;
import com.google.gson.JsonSerializationContext;
import com.google.protobuf.Descriptors.FieldDescriptor;
import com.google.protobuf.Descriptors.FieldDescriptor.Type;
import com.google.protobuf.Descriptors.EnumValueDescriptor;
import com.google.protobuf.Message;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.lang.reflect.Type as ReflectType;
import java.util.*;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.ArgumentCaptor;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class ProtoTypeAdapterTest {

  private ProtoTypeAdapter adapter;
  private JsonSerializationContext context;

  @BeforeEach
  void setUp() {
    adapter = ProtoTypeAdapter.newBuilder()
        .build();
    context = mock(JsonSerializationContext.class);
  }

  @Test
  void serialize_emptyMessage_returnsEmptyJsonObject() {
    Message src = mock(Message.class);
    when(src.getAllFields()).thenReturn(Collections.emptyMap());

    JsonElement result = adapter.serialize(src, Object.class, context);

    assertTrue(result.isJsonObject());
    assertEquals(0, result.getAsJsonObject().entrySet().size());
  }

  @Test
  void serialize_nonEnumField_serializesValueDirectly() {
    Message src = mock(Message.class);
    FieldDescriptor fieldDescriptor = mock(FieldDescriptor.class);
    Object fieldValue = new Object();

    Map<FieldDescriptor, Object> fields = new HashMap<>();
    fields.put(fieldDescriptor, fieldValue);

    when(src.getAllFields()).thenReturn(fields);
    when(fieldDescriptor.getType()).thenReturn(Type.INT32);
    when(fieldDescriptor.getOptions()).thenReturn(null);
    when(fieldDescriptor.getName()).thenReturn("fieldName");

    JsonElement serializedValue = mock(JsonElement.class);
    when(context.serialize(fieldValue)).thenReturn(serializedValue);

    JsonElement result = adapter.serialize(src, Object.class, context);

    assertTrue(result.isJsonObject());
    JsonObject obj = result.getAsJsonObject();
    assertTrue(obj.has("fieldName"));
    assertEquals(serializedValue, obj.get("fieldName"));
  }

  @Test
  void serialize_enumField_singleEnumValue_serializesEnumValue() throws Exception {
    Message src = mock(Message.class);
    FieldDescriptor fieldDescriptor = mock(FieldDescriptor.class);
    EnumValueDescriptor enumValueDescriptor = mock(EnumValueDescriptor.class);

    Map<FieldDescriptor, Object> fields = new HashMap<>();
    fields.put(fieldDescriptor, enumValueDescriptor);

    when(src.getAllFields()).thenReturn(fields);
    when(fieldDescriptor.getType()).thenReturn(Type.ENUM);
    when(fieldDescriptor.getOptions()).thenReturn(null);
    when(fieldDescriptor.getName()).thenReturn("enumField");

    // Spy adapter to mock getEnumValue
    ProtoTypeAdapter spyAdapter = Mockito.spy(adapter);
    Object enumValue = "enumValue";
    doReturn(enumValue).when(spyAdapter).getEnumValue(enumValueDescriptor);

    JsonElement serializedEnumValue = mock(JsonElement.class);
    when(context.serialize(enumValue)).thenReturn(serializedEnumValue);

    JsonElement result = spyAdapter.serialize(src, Object.class, context);

    assertTrue(result.isJsonObject());
    JsonObject obj = result.getAsJsonObject();
    assertTrue(obj.has("enumField"));
    assertEquals(serializedEnumValue, obj.get("enumField"));
  }

  @Test
  void serialize_enumField_collectionEnumValues_serializesArray() throws Exception {
    Message src = mock(Message.class);
    FieldDescriptor fieldDescriptor = mock(FieldDescriptor.class);
    EnumValueDescriptor enumValueDescriptor1 = mock(EnumValueDescriptor.class);
    EnumValueDescriptor enumValueDescriptor2 = mock(EnumValueDescriptor.class);

    Collection<EnumValueDescriptor> enumCollection = Arrays.asList(enumValueDescriptor1, enumValueDescriptor2);

    Map<FieldDescriptor, Object> fields = new HashMap<>();
    fields.put(fieldDescriptor, enumCollection);

    when(src.getAllFields()).thenReturn(fields);
    when(fieldDescriptor.getType()).thenReturn(Type.ENUM);
    when(fieldDescriptor.getOptions()).thenReturn(null);
    when(fieldDescriptor.getName()).thenReturn("enumCollectionField");

    ProtoTypeAdapter spyAdapter = Mockito.spy(adapter);

    Object enumValue1 = "enumValue1";
    Object enumValue2 = "enumValue2";
    doReturn(enumValue1).when(spyAdapter).getEnumValue(enumValueDescriptor1);
    doReturn(enumValue2).when(spyAdapter).getEnumValue(enumValueDescriptor2);

    JsonElement serializedEnumValue1 = mock(JsonElement.class);
    JsonElement serializedEnumValue2 = mock(JsonElement.class);

    when(context.serialize(enumValue1)).thenReturn(serializedEnumValue1);
    when(context.serialize(enumValue2)).thenReturn(serializedEnumValue2);

    JsonElement result = spyAdapter.serialize(src, Object.class, context);

    assertTrue(result.isJsonObject());
    JsonObject obj = result.getAsJsonObject();
    assertTrue(obj.has("enumCollectionField"));
    JsonArray array = obj.getAsJsonArray("enumCollectionField");
    assertEquals(2, array.size());
    assertEquals(serializedEnumValue1, array.get(0));
    assertEquals(serializedEnumValue2, array.get(1));
  }

  @Test
  void serialize_getCustSerializedNameUsed() throws Exception {
    Message src = mock(Message.class);
    FieldDescriptor fieldDescriptor = mock(FieldDescriptor.class);
    Object fieldValue = new Object();

    Map<FieldDescriptor, Object> fields = new HashMap<>();
    fields.put(fieldDescriptor, fieldValue);

    when(src.getAllFields()).thenReturn(fields);
    when(fieldDescriptor.getType()).thenReturn(Type.STRING);
    when(fieldDescriptor.getOptions()).thenReturn(null);
    when(fieldDescriptor.getName()).thenReturn("originalName");

    ProtoTypeAdapter spyAdapter = Mockito.spy(adapter);

    // Use reflection to invoke private getCustSerializedName and spy on it
    Method method = ProtoTypeAdapter.class.getDeclaredMethod("getCustSerializedName", 
        com.google.protobuf.DescriptorProtos.FieldOptions.class, String.class);
    method.setAccessible(true);

    doReturn("customName").when(spyAdapter).getCustSerializedName(null, "originalName");

    JsonElement serializedValue = mock(JsonElement.class);
    when(context.serialize(fieldValue)).thenReturn(serializedValue);

    JsonElement result = spyAdapter.serialize(src, Object.class, context);

    assertTrue(result.isJsonObject());
    JsonObject obj = result.getAsJsonObject();
    assertTrue(obj.has("customName"));
    assertEquals(serializedValue, obj.get("customName"));
  }
}
